SELECT me.* FROM makeup_exam me
LEFT JOIN exam e ON me.exam_id=e.id
LEFT JOIN user u ON me.user_id=u.id
WHERE me.deleted=0
AND me.user_id=#{userId}
AND e.course_id=#{courseId}
AND u.dept_id=#{deptId}
ORDER BY me.id DESC LIMIT #{offset()},#{pageSize}

SELECT COUNT(1) FROM makeup_exam me
LEFT JOIN exam e ON me.exam_id=e.id
LEFT JOIN user u ON me.user_id=u.id
WHERE me.deleted=0
AND me.user_id=#{userId}
AND e.course_id=#{courseId}
AND u.dept_id=#{deptId}
